import logging
import logging.handlers
import os

# Define the log directory
LOG_DIR = '/var/log/application'

# Ensure the log directory exists
os.makedirs(LOG_DIR, exist_ok=True)

# Define log file paths
APP_LOG_FILE = os.path.join(LOG_DIR, 'application.log')
ERROR_LOG_FILE = os.path.join(LOG_DIR, 'error.log')

# Define log formatters
# Standard formatter for application logs
standard_formatter = logging.Formatter(
    '%(asctime)s - %(name)s - %(levelname)s - %(filename)s:%(lineno)d - %(message)s'
)
# Simple formatter for console output (optional, good for dev/testing)
console_formatter = logging.Formatter(
    '%(levelname)s - %(name)s - %(message)s'
)

# Get the root logger
root_logger = logging.getLogger()
root_logger.setLevel(logging.INFO)  # Set default level for the root logger

# --- Handlers ---

# 1. File Handler for all application logs (INFO and above)
app_file_handler = logging.handlers.RotatingFileHandler(
    APP_LOG_FILE,
    maxBytes=10 * 1024 * 1024,  # 10 MB per file
    backupCount=5,              # Keep 5 backup files (application.log.1, .2, etc.)
    encoding='utf-8'
)
app_file_handler.setLevel(logging.INFO)
app_file_handler.setFormatter(standard_formatter)
root_logger.addHandler(app_file_handler)

# 2. File Handler for ERROR level logs specifically
error_file_handler = logging.handlers.RotatingFileHandler(
    ERROR_LOG_FILE,
    maxBytes=2 * 1024 * 1024,  # 2 MB per file
    backupCount=3,             # Keep 3 backup files
    encoding='utf-8'
)
error_file_handler.setLevel(logging.ERROR)
error_file_handler.setFormatter(standard_formatter)
root_logger.addHandler(error_file_handler)

# 3. Console Handler (optional, for immediate feedback during development/testing)
# In a production environment, you might remove or set its level higher (e.g., WARNING)
console_handler = logging.StreamHandler()
console_handler.setLevel(logging.WARNING) # Only show WARNING and above on console in prod
console_handler.setFormatter(console_formatter)
root_logger.addHandler(console_handler)

# --- Example Usage ---
# You can get a specific logger for your module/application part
logger = logging.getLogger(__name__)

if __name__ == '__main__':
    logger.debug("This is a debug message - won't be logged by default (level INFO)")
    logger.info("This is an informational message.")
    logger.warning("This is a warning message.")
    logger.error("This is an error message, it will go to both app.log and error.log.")
    logger.exception("This is an exception message, often used with try-except blocks.")

    try:
        1 / 0
    except ZeroDivisionError:
        logger.exception("An error occurred during division!")

    logger.critical("This is a critical message.")

